document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelectorAll(".blog-filter-btn"),t=document.querySelectorAll(".blog-card");e.length&&t.length&&e.forEach(a=>{a.addEventListener("click",()=>{e.forEach(e=>e.classList.remove("active")),a.classList.add("active");const c=a.dataset.filter;t.forEach(e=>{"all"===c||e.dataset.category===c?e.classList.remove("hidden"):e.classList.add("hidden")})})})});